import pytest
from slugify import slugify


class TestSlugifyHappyPath:
    """Tests for typical use cases."""

    def test_simple_text(self):
        assert slugify("Hello World") == "hello-world"

    def test_multiple_words(self):
        assert slugify("The Quick Brown Fox") == "the-quick-brown-fox"

    def test_mixed_case(self):
        assert slugify("HeLLo WoRLd") == "hello-world"

    def test_text_with_underscores(self):
        assert slugify("hello_world") == "hello-world"

    def test_text_with_numbers(self):
        assert slugify("Test123") == "test123"

    def test_leading_trailing_whitespace(self):
        assert slugify("  hello  ") == "hello"

    def test_leading_whitespace_only(self):
        assert slugify("   hello") == "hello"


class TestSlugifyEdgeCases:
    """Tests for edge cases and boundary conditions."""

    def test_empty_string(self):
        assert slugify("") == ""

    def test_whitespace_only(self):
        assert slugify("   ") == ""

    def test_multiple_spaces(self):
        assert slugify("hello   world") == "hello-world"

    def test_multiple_underscores(self):
        assert slugify("hello___world") == "hello-world"

    def test_multiple_hyphens(self):
        assert slugify("hello---world") == "hello-world"

    def test_leading_hyphens(self):
        assert slugify("---hello") == "hello"

    def test_trailing_hyphens(self):
        assert slugify("hello---") == "hello"

    def test_both_leading_and_trailing_hyphens(self):
        assert slugify("---hello---") == "hello"

    def test_mixed_separators(self):
        assert slugify("hello _ world - test") == "hello-world-test"

    def test_only_hyphens(self):
        assert slugify("---") == ""

    def test_single_character(self):
        assert slugify("A") == "a"

    def test_single_space(self):
        assert slugify(" ") == ""

    def test_newlines_in_text(self):
        assert slugify("hello\nworld") == "hello-world"

    def test_tabs_in_text(self):
        assert slugify("hello\tworld") == "hello-world"


class TestSlugifySpecialCharacters:
    """Tests for special characters and symbols."""

    def test_special_characters_removed(self):
        assert slugify("hello@world") == "helloworld"

    def test_special_characters_multiple(self):
        assert slugify("foo!bar?baz") == "foobarbaz"

    def test_punctuation_removed(self):
        assert slugify("price: $100") == "price-100"

    def test_parentheses_removed(self):
        assert slugify("Hello (World)") == "hello-world"

    def test_brackets_removed(self):
        assert slugify("test[1]") == "test1"

    def test_slashes_removed(self):
        assert slugify("path/to/file") == "pathtofile"

    def test_backslashes_removed(self):
        assert slugify("path\\to\\file") == "pathtofile"

    def test_dots_removed(self):
        assert slugify("file.name.txt") == "filename-txt"

    def test_ampersand_converted(self):
        assert slugify("rock & roll") == "rock-roll"

    def test_equals_sign_removed(self):
        assert slugify("a = b") == "a-b"

    def test_plus_sign_removed(self):
        assert slugify("c++") == "c"


class TestSlugifyUnicode:
    """Tests for Unicode character handling."""

    def test_unicode_characters_removed(self):
        assert slugify("café") == "caf"

    def test_unicode_accent_converted(self):
        assert slugify("naïve") == "naive"

    def test_spanish_n_converted(self):
        assert slugify("Ñoño") == "noo"

    def test_emoji_removed(self):
        assert slugify("🎉 Party 🎊") == "party"

    def test_chinese_characters_removed(self):
        assert slugify("Hello 世界") == "hello"


class TestSlugifyErrorCases:
    """Tests for invalid input handling."""

    def test_none_raises_type_error(self):
        with pytest.raises(TypeError):
            slugify(None)

    def test_integer_raises_type_error(self):
        with pytest.raises(TypeError):
            slugify(123)

    def test_float_raises_type_error(self):
        with pytest.raises(TypeError):
            slugify(12.5)

    def test_list_raises_type_error(self):
        with pytest.raises(TypeError):
            slugify(["hello", "world"])


class TestSlugifyRealWorldExamples:
    """Tests for realistic use cases like titles, URLs, etc."""

    def test_blog_post_title(self):
        assert slugify("10 Tips for Better Code") == "10-tips-for-better-code"

    def test_company_name(self):
        assert slugify("John's Bar & Grill™") == "johns-bar-grill"

    def test_file_name(self):
        assert slugify("photo (1).jpg") == "photo-1-jpg"

    def test_category_name(self):
        assert slugify("Electronics & Gadgets") == "electronics-gadgets"

    def test_location_name(self):
        assert slugify("New York, NY (USA)") == "new-york-ny-usa"

    def test_version_string(self):
        assert slugify("v1.2.3") == "v1-2-3"
